<template><div class="layout-root"><header class="topbar"><div class="title-container"><img src="/img/logo.png" alt="logo" class="header-logo"><h1>Qiongjing Cosmora</h1></div><el-menu class="top-menu" mode="horizontal" :default-active="activeMenu" router><el-menu-item index="/app/full-chain"><span slot="title">Learn Loop</span></el-menu-item><el-menu-item index="/app/learning-path"><span slot="title">Learn Path</span></el-menu-item><el-menu-item index="/app/knowledge-quiz"><span slot="title">Quiz</span></el-menu-item><el-menu-item index="/app/ai-tutor"><span slot="title">AI Tutor</span></el-menu-item><el-menu-item index="/app/ai-doc"><span slot="title">Read</span></el-menu-item><el-menu-item index="/app/ai-media"><span slot="title">Generate</span></el-menu-item></el-menu><div class="header-right"><div class="user-info"><span class="user-dropdown-link"><span class="user-name">{{userName}}</span><el-avatar :size="40" :src="userAvatar"></el-avatar></span><button class="header-action-btn" @click="$router.push({name:'Profile'})">Profile</button><button class="header-action-btn danger" @click="logout">Logout</button></div></div></header><main class="content"><router-view class="page-view"></router-view></main></div></template><script>export default{name:'App',created(){const u=JSON.parse(localStorage.getItem('user'));if(u){this.userName=u.username||u.userId;this.userAvatar=u.avatar||'/yu-avatar.png'}},data(){return{userName:'',userAvatar:'/yu-avatar.png'}},computed:{activeMenu(){return this.$route.path}},methods:{logout(){localStorage.removeItem('user');this.$router.push('/login')}}}</script>